#check if a point p in ZZ^d is a + ZF, where F is a face of a semigroup 
function is_in_aZF(a::Vector{Int},F::FaceQ,p::Vector{Int})
    if F.A === nothing
        return a == p
    else
        A = vcat(F.A,-F.A)
        #we want to check if p is in a + ZF, where F is a face of the semigroup generated by the columns of A
        #this is equivalent to checking if p is in the semigroup generated by the columns of A and -A
        b = vcat(p .- a,-p .+ a)
        P = polyhedron(A,b)
        milp = mixed_integer_linear_program(P,zeros(Int64,size(A,2)))
        return solve_milp(milp) != (nothing,nothing)
    end
end

# check if the intersection (g+Q)\cap (b + ZF) is non-empty 
function in_intersection(kQ::MonoidAlgebra,g::Vector{Int},a::Vector{Int},F::FaceQ)
    n = ngens(kQ)
    _D = [degree(Vector{Int},g) for g in gens(kQ)]
    D = hcat(_D...)
    if F.A === nothing
        _A = vcat(D,-D)
        #add positivity constraints
        A = vcat(_A,I_n(n),-I_n(n))
    else 
        _A = vcat(hcat(F.A,-D),hcat(-F.A,D))
        #add positivity constraints
        A = vcat(_A,hcat(zeros(Int64,n,size(F.A,2)),I_n(n)),hcat(zeros(Int64,n,size(F.A,2)),-I_n(n)))
    end
    b = vcat(a-g,-a+g, zeros(Int64,2*n))
    P = polyhedron(A,b)
    milp = mixed_integer_linear_program(P,zeros(Int64,size(A,2)))
    return solve_milp(milp) != (nothing,nothing)
end

kQ = monoid_algebra([[2,0],[0,1],[1,1]],QQ)
